SELECT *
FROM player_game_statistics_versions
WHERE game_id = 1 AND player_id = 0;

SELECT home_points AS HomeScore, away_points AS AwayScore
FROM games
WHERE game_id = 0;

SELECT 
  (SELECT AVG(home_points) FROM games WHERE home_team = 'Team A') AS avg_home_points,
  (SELECT AVG(away_points) FROM games WHERE away_team = 'Team A') AS avg_away_points;

SELECT AVG(assist_percentage) AS avg_assist_percentage
FROM game_statistics
WHERE game_id = 1 AND team_id = 1;
